const cfg = $('Set API and Search Parameters').first().json;
const maxItems = Math.max(1, Number(cfg.maxItems || 1));
const token = cfg.token;
const baseUrl = cfg.baseUrl;
const keyword = cfg.keyword;

// Real tested search-item-list/v1 response path:
// root.data.model.itemList[]
const rows = $input.all();
const selectedProducts = [];

for (const row of rows) {
  const itemList = row.json?.data?.model?.itemList;

  if (!Array.isArray(itemList)) {
    continue;
  }

  for (const product of itemList) {
    const itemId = product?.itemId;

    if (itemId !== undefined && itemId !== null && String(itemId).trim() !== '') {
      selectedProducts.push(product);
    }
  }
}

const limitedProducts = selectedProducts.slice(0, maxItems);

return limitedProducts.map((product, index) => ({
  json: {
    baseUrl,
    token,
    keyword,
    itemId: String(product.itemId),
    itemRank: index + 1,
    selectedBy: 'search-item-list-v1:data.model.itemList',
    searchProduct: {
      itemId: product.itemId ?? '',
      itemName: product.itemName || '',
      itemSubName: product.itemSubName || '',
      itemType: product.itemType || '',
      priceYuanDouble: product.priceYuanDouble ?? null,
      priceZKYuanDouble: product.priceZKYuanDouble ?? null,
      discntPriceYuan: product.discntPriceYuan ?? null,
      discntType: product.discntType || '',
      orderPayUV: product.orderPayUV || '',
      frontStock: product.frontStock ?? null,
      shopId: product.shopId ?? '',
      shopName: product.shopName || '',
      sellerLoc: product.sellerLoc || '',
      itemLoc: product.itemLoc || '',
      picUrlFull: product.picUrlFull || '',
      picUrlList: Array.isArray(product.picUrlList) ? product.picUrlList : [],
      raw: product
    }
  }
}));

const rows = $input.all();
const cfg = $('Set API and Search Parameters').first().json;
const selectedRows = $('Extract Product IDs from Results').all();

function toNumberOrNull(value) {
  if (value === undefined || value === null || value === '') return null;
  const num = Number(value);
  return Number.isFinite(num) ? num : null;
}

function fenToYuan(value) {
  const num = toNumberOrNull(value);
  return num === null ? null : num / 100;
}

return rows.map((item, index) => {
  const root = item.json || {};
  const detail = root.data || {};
  const selected = selectedRows[index]?.json || {};
  const searchProduct = selected.searchProduct || {};

  const skus = Array.isArray(detail.sku2info) ? detail.sku2info : [];
  const skuProperties = Array.isArray(detail.skuBase) ? detail.skuBase : [];

  const cleanedSkus = skus.map(sku => ({
    skuId: sku.skuId || '',
    skuName: sku.skuName || '',
    skuPicUrl: sku.skuPicUrl || '',
    itemPriceFen: sku.itemPrice ?? null,
    itemPriceYuan: fenToYuan(sku.itemPrice),
    finalSkuPriceFen: sku.finalSkuPrice ?? null,
    finalSkuPriceYuan: fenToYuan(sku.finalSkuPrice),
    finalPriceFen: sku.finalPrice ?? null,
    finalPriceYuan: fenToYuan(sku.finalPrice),
    thirdOriginalDiscountPriceFen: sku.thirdOriginalDiscountPrice ?? null,
    thirdOriginalDiscountPriceYuan: fenToYuan(sku.thirdOriginalDiscountPrice),
    stock: sku.stock ?? '',
    valueList: Array.isArray(sku.valueList) ? sku.valueList : []
  }));

  const finalSkuPrices = cleanedSkus
    .map(sku => sku.finalSkuPriceFen)
    .filter(value => typeof value === 'number');

  const totalStock = cleanedSkus.reduce((sum, sku) => {
    const stockNum = Number(sku.stock);
    return Number.isFinite(stockNum) ? sum + stockNum : sum;
  }, 0);

  const cleanedSkuProperties = skuProperties.map(property => ({
    propertyId: property.propertyId || '',
    propertyName: property.propertyName || '',
    values: Array.isArray(property.itemPropertyValues)
      ? property.itemPropertyValues.map(value => ({
          valueId: value.valueId || '',
          value: value.value || '',
          pic: value.pic || '',
          badge: value.badge ?? null
        }))
      : []
  }));

  return {
    json: {
      requestedKeyword: cfg.keyword || '',
      searchEndpoint: '/api/taobao/search-item-list/v1',
      detailEndpoint: '/api/taobao/get-item-detail/v4',
      selectedItemId: selected.itemId || String(detail.itemId || ''),
      selectedBy: selected.selectedBy || '',
      product: {
        itemId: detail.itemId ?? '',
        title: detail.title || '',
        itemPic: detail.itemPic || '',
        images: Array.isArray(detail.images) ? detail.images : [],
        itemPriceFen: detail.itemPrice ?? null,
        itemPriceYuan: fenToYuan(detail.itemPrice),
        discountPriceFen: detail.DiscountPrice ?? null,
        discountPriceYuan: fenToYuan(detail.DiscountPrice),
        shopName: detail.shopName || '',
        shopType: detail.shopType || ''
      },
      skuSummary: {
        skuCount: cleanedSkus.length,
        skuPropertyCount: cleanedSkuProperties.length,
        minFinalSkuPriceFen: finalSkuPrices.length ? Math.min(...finalSkuPrices) : null,
        minFinalSkuPriceYuan: finalSkuPrices.length ? Math.min(...finalSkuPrices) / 100 : null,
        maxFinalSkuPriceFen: finalSkuPrices.length ? Math.max(...finalSkuPrices) : null,
        maxFinalSkuPriceYuan: finalSkuPrices.length ? Math.max(...finalSkuPrices) / 100 : null,
        totalStock
      },
      skus: cleanedSkus,
      skuProperties: cleanedSkuProperties,
      searchSourceProduct: searchProduct,
      raw: root
    }
  };
});
